mapper.select:
select o.order_id, o.delivery_id, d.delivery_date, r.route_name, d.status as delivery_status, o.customer_id, c.name as customer_name, c.phone as customer_phone, o.total_amount, o.received_amount, o.unpaid_amount, o.remark from biz_customer_order o left join biz_delivery_order d on o.delivery_id = d.delivery_id left join biz_route r on d.route_id = r.route_id left join biz_customer c on o.customer_id = c.customer_id where o.customer_id = #{customerId}
and d.delivery_date >= #{beginDate}
and d.delivery_date <= #{endDate}
order by d.delivery_date desc, o.order_id desc

select count(*) as order_count,
       coalesce(sum(o.total_amount), 0) as total_amount
from biz_customer_order o
left join biz_delivery_order d on o.delivery_id = d.delivery_id
where o.customer_id = #{customerId}

    and d.delivery_date >= #{beginDate}


    and d.delivery_date <= #{endDate}
